            for (j = i + 1; j <= B; j++) {
                int cnt1 = 0, cnt2 = 0;
                for (l = 1; l <= N; l++) {
                    for (m = 1; m <= N; m++) {
                        int sum = 0;
                        for (n = 1; n <= N; n++) {
                            sum += Q[i][l][n] * Q[j][m][n];
                        }
