                            sum += Q[i][l][n] * Q[j][m][n];
                        }
                        if (sum % 2 == 0) cnt2++;
                    }
                }
                if (cnt1 > cnt2) ans++;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

